package com.vidaysalud.veterinaria.inventarioservicio.client;import com.vidaysalud.veterinaria.inventarioservicio.exception.*;import com.fasterxml.jackson.databind.JsonNode;import lombok.RequiredArgsConstructor;import org.springframework.beans.factory.annotation.Value;import org.springframework.http.MediaType;import org.springframework.stereotype.Component;import org.springframework.web.reactive.function.client.*;import java.time.Duration;import java.util.Map;@Component @RequiredArgsConstructor public class MedicamentoClient{private final WebClient.Builder builder;@Value("${servicios.medicamento.url}")private String baseUrl;public int obtenerStock(Integer id){try{JsonNode n=builder.build().get().uri(baseUrl+"/"+id).retrieve().bodyToMono(JsonNode.class).block(Duration.ofSeconds(4));if(n==null||n.path("data").isMissingNode())throw new ServicioRemotoException("Respuesta inválida de medicamento-servicio");return n.path("data").path("stock").asInt();}catch(WebClientResponseException.NotFound e){throw new ReglaNegocioException("Medicamento no existe: "+id);}catch(WebClientRequestException e){throw new ServicioRemotoException("No fue posible conectar con medicamento-servicio");}}public void actualizarStock(Integer id,Integer stock){try{builder.build().patch().uri(baseUrl+"/"+id+"/stock").contentType(MediaType.APPLICATION_JSON).bodyValue(Map.of("stock",stock)).retrieve().toBodilessEntity().block(Duration.ofSeconds(4));}catch(WebClientRequestException e){throw new ServicioRemotoException("No fue posible actualizar stock remoto");}catch(Exception e){throw new ServicioRemotoException("Error actualizando stock remoto");}}}